const now = new Date().toISOString().slice(0, 10);
const first = $input.first()?.json ?? {};
const hits = Array.isArray(first.hits) ? first.hits : [];

function ymd(value) {
  if (!value) return '';
  return String(value).slice(0, 10);
}

return hits.map((hit) => {
  const recordId = String(hit.objectID ?? '');
  const url = hit.url || `https://news.ycombinator.com/item?id=${recordId}`;
  const title = hit.title || hit.story_title || '';
  const points = Number(hit.points ?? 0);
  const comments = Number(hit.num_comments ?? 0);

  return {
    json: {
      record_id: recordId,
      source_name: 'hacker_news',
      source_type: 'discussion',
      title,
      text: '',
      author: hit.author || '',
      url,
      posted_at: ymd(hit.created_at),
      engagement_score: points + comments,
      comments_count: comments,
      tags: 'ai agents',
      content_hash: `hacker_news|${title}|${url}`,
      collected_at: now,
      quality_status: 'unchecked'
    }
  };
});

const now = new Date().toISOString().slice(0, 10);
const incoming = $input.all();
const records = incoming.length === 1 && Array.isArray(incoming[0].json)
  ? incoming[0].json
  : incoming.map((item) => item.json);

function ymd(value) {
  if (!value) return '';
  return String(value).slice(0, 10);
}

return records.map((article) => {
  const recordId = String(article.id ?? '');
  const title = article.title || '';
  const url = article.url || article.canonical_url || '';
  const reactions = Number(article.positive_reactions_count ?? 0);
  const comments = Number(article.comments_count ?? 0);
  const tags = Array.isArray(article.tag_list) ? article.tag_list.join(', ') : String(article.tag_list ?? '');

  return {
    json: {
      record_id: recordId,
      source_name: 'dev_to',
      source_type: 'developer_article',
      title,
      text: article.description || '',
      author: article.user?.username || article.user?.name || '',
      url,
      posted_at: ymd(article.published_at || article.created_at),
      engagement_score: reactions + comments,
      comments_count: comments,
      tags,
      content_hash: `dev_to|${title}|${url}`,
      collected_at: now,
      quality_status: 'unchecked'
    }
  };
});

const now = new Date().toISOString().slice(0, 10);
const first = $input.first()?.json ?? {};
const repos = Array.isArray(first.items) ? first.items : [];

function ymd(value) {
  if (!value) return '';
  return String(value).slice(0, 10);
}

return repos.map((repo) => {
  const recordId = String(repo.id ?? '');
  const title = repo.full_name || repo.name || '';
  const url = repo.html_url || '';
  const stars = Number(repo.stargazers_count ?? 0);
  const forks = Number(repo.forks_count ?? 0);

  return {
    json: {
      record_id: recordId,
      source_name: 'github',
      source_type: 'developer_repo',
      title,
      text: repo.description || '',
      author: repo.owner?.login || '',
      url,
      posted_at: ymd(repo.pushed_at || repo.updated_at || repo.created_at),
      engagement_score: stars + forks,
      comments_count: 0,
      tags: repo.language || '',
      content_hash: `github|${title}|${url}`,
      collected_at: now,
      quality_status: 'unchecked'
    }
  };
});

const required = ['record_id', 'source_name', 'title', 'url', 'posted_at'];
const seen = new Set();
const sourceCounts = {};
let duplicateRowsRemoved = 0;
let incompleteRowsRemoved = 0;

const cleaned = [];

for (const item of $input.all()) {
  const row = { ...item.json };
  row.posted_at = row.posted_at ? String(row.posted_at).slice(0, 10) : '';
  row.collected_at = row.collected_at ? String(row.collected_at).slice(0, 10) : new Date().toISOString().slice(0, 10);

  const missingRequired = required.some((field) => !row[field]);
  if (missingRequired) {
    incompleteRowsRemoved += 1;
    continue;
  }

  const dedupeKey = `${row.source_name}:${row.record_id}`;
  if (seen.has(dedupeKey)) {
    duplicateRowsRemoved += 1;
    continue;
  }
  seen.add(dedupeKey);

  row.quality_status = 'complete';
  sourceCounts[row.source_name] = (sourceCounts[row.source_name] || 0) + 1;
  cleaned.push(row);
}

const totalBeforeCleaning = $input.all().length;
const cleanRecords = cleaned.length;
const qualityRate = totalBeforeCleaning === 0 ? 0 : Number(((cleanRecords / totalBeforeCleaning) * 100).toFixed(1));

const summary = {
  record_id: 'QUALITY_SUMMARY',
  source_name: 'summary',
  source_type: 'quality_report',
  title: `Quality summary: ${cleanRecords}/${totalBeforeCleaning} clean records (${qualityRate}%)`,
  text: `Sources=${Object.keys(sourceCounts).length}; sourceCounts=${JSON.stringify(sourceCounts)}; incompleteRowsRemoved=${incompleteRowsRemoved}; duplicateRowsRemoved=${duplicateRowsRemoved}`,
  author: 'n8n workflow',
  url: 'local-quality-summary',
  posted_at: new Date().toISOString().slice(0, 10),
  engagement_score: cleanRecords,
  comments_count: 0,
  tags: 'quality summary',
  content_hash: `summary|${cleanRecords}|${qualityRate}`,
  collected_at: new Date().toISOString().slice(0, 10),
  quality_status: 'complete'
};

return [...cleaned, summary].map((row) => ({ json: row }));
